import React, { useState, useEffect, useRef } from 'react';
import { useHistory } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import '../styles/AdminSidebar.css';

// Ant Design imports
import {
  Layout, Menu, Card, Table, Button, Form, Input, Upload, Modal, Select,
  Tabs, Progress, notification, Tag, Space, Divider, Row, Col, Statistic,
  DatePicker, Switch, InputNumber, Spin, Alert, Typography, Rate,
  Drawer, Breadcrumb, Empty, List, Timeline, Tooltip, Avatar, Badge,
  Popconfirm, message, Descriptions, Steps, Collapse, Dropdown, Slider,
  Checkbox, Radio, AutoComplete, Cascader, TimePicker, Transfer, TreeSelect
} from 'antd';

import {
  PlusOutlined, EditOutlined, DeleteOutlined, UploadOutlined,
  DownloadOutlined, FileOutlined, VideoCameraOutlined, AudioOutlined,
  QuestionCircleOutlined, CheckCircleOutlined, CloseCircleOutlined,
  EyeOutlined, SearchOutlined, FilterOutlined, BookOutlined,
  FileTextOutlined, PlayCircleOutlined, HomeOutlined, UserOutlined,
  BarChartOutlined, CalendarOutlined, BellOutlined, SettingOutlined,
  MenuFoldOutlined, MenuUnfoldOutlined, StarOutlined, ClockCircleOutlined,
  TrophyOutlined, MessageOutlined, TeamOutlined, DashboardOutlined,
  SolutionOutlined, FundOutlined, PieChartOutlined, LineChartOutlined,
  AreaChartOutlined, RadarChartOutlined, HeatMapOutlined, DotChartOutlined,
  GlobalOutlined, MailOutlined, PhoneOutlined, EnvironmentOutlined,
  SafetyOutlined, LockOutlined, KeyOutlined, CloudOutlined, DatabaseOutlined,
  ApiOutlined, CodeOutlined, BugOutlined, ToolOutlined, ExperimentOutlined,
  RocketOutlined, ThunderboltOutlined, FireOutlined, GiftOutlined,
  HeartOutlined, SmileOutlined, FrownOutlined, MehOutlined,
  LikeOutlined, DislikeOutlined, CommentOutlined, ShareAltOutlined,
  SaveOutlined, PrinterOutlined, ScanOutlined, WifiOutlined,
  SoundOutlined, NotificationOutlined, WarningOutlined, InfoCircleOutlined,
  ExclamationCircleOutlined, StopOutlined, PauseCircleOutlined,
  ForwardOutlined, BackwardOutlined, FastForwardOutlined, FastBackwardOutlined,
  StepForwardOutlined, StepBackwardOutlined, CaretRightOutlined,
  CaretLeftOutlined, CaretUpOutlined, CaretDownOutlined,
  FullscreenOutlined, FullscreenExitOutlined, ExpandOutlined,
  CompressOutlined, PlusCircleOutlined, MinusCircleOutlined,
  CheckSquareOutlined, BorderOutlined, FormOutlined, HighlightOutlined,
  SnippetsOutlined, DiffOutlined, CopyOutlined, ScissorOutlined,
  DeleteRowOutlined, MergeCellsOutlined, SplitCellsOutlined,
  AppstoreOutlined, BarsOutlined, BuildOutlined, BlockOutlined,
  GatewayOutlined, ClusterOutlined, DeploymentUnitOutlined,
  VerifiedOutlined, SafetyCertificateOutlined, SecurityScanOutlined,
  IdcardOutlined, ContactsOutlined, FolderOutlined, FolderOpenOutlined,
  FolderAddOutlined, HddOutlined, CloudServerOutlined, CloudSyncOutlined,
  CloudDownloadOutlined, CloudUploadOutlined, InboxOutlined, LaptopOutlined,
  MobileOutlined, TabletOutlined, DesktopOutlined, WalletOutlined,
  BankOutlined, CreditCardOutlined, DollarOutlined, EuroOutlined,
  PoundOutlined, TransactionOutlined, MoneyCollectOutlined,
  FieldTimeOutlined, HistoryOutlined, ReloadOutlined, SyncOutlined,
  RedoOutlined, UndoOutlined, LoginOutlined, LogoutOutlined,
  UserAddOutlined, UserDeleteOutlined, UsergroupAddOutlined,
  UsergroupDeleteOutlined, ManOutlined, WomanOutlined,
  ShoppingCartOutlined, ShoppingOutlined, ShopOutlined,
  TagsOutlined, BarcodeOutlined, QrcodeOutlined,
  CameraOutlined, PictureOutlined, CompassOutlined,
  AimOutlined, SendOutlined, RiseOutlined,
  FallOutlined, StockOutlined, FundProjectionScreenOutlined,
  PercentageOutlined, TagOutlined
} from '@ant-design/icons';

import moment from 'moment';
import { Line, Bar, Doughnut, Radar, Pie } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  ArcElement,
  RadialLinearScale,
  Title as ChartTitle,
  Tooltip as ChartTooltip,
  Legend,
  Filler
} from 'chart.js';

// Register Chart.js components
ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  BarElement,
  ArcElement,
  RadialLinearScale,
  ChartTitle,
  ChartTooltip,
  Legend,
  Filler
);

// Import API clients
import { authAPI, statsAPI, courseAPI, materialAPI, quizAPI, homeworkAPI, userAPI } from '../utils/apiClient';

const { Header, Sider, Content } = Layout;
const { Title, Text, Paragraph } = Typography;
const { TabPane } = Tabs;
const { Option } = Select;
const { TextArea } = Input;
const { Dragger } = Upload;
const { RangePicker } = DatePicker;
const { Panel } = Collapse;
const { Step } = Steps;
const { Meta } = Card;
const { SubMenu } = Menu;
const { confirm } = Modal;

// API Configuration
const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000';

// Helper function to get auth headers
const getAuthHeaders = () => {
  const token = localStorage.getItem('authToken') || localStorage.getItem('token');
  return {
    'Authorization': token ? `Bearer ${token}` : '',
    'Content-Type': 'application/json'
  };
};

// Main Dashboard Component
const AdminFacultyDashboard = () => {
  const { t } = useTranslation();
  const history = useHistory();
  
  // States
  const [collapsed, setCollapsed] = useState(false);
  const [currentUser, setCurrentUser] = useState(null);
  const [loading, setLoading] = useState(true);
  const [activeKey, setActiveKey] = useState('overview');
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);
  const [theme, setTheme] = useState('dark');
  
  // Dashboard data states
  const [dashboardStats, setDashboardStats] = useState({
    totalCourses: 0,
    totalStudents: 0,
    totalMaterials: 0,
    pendingSubmissions: 0,
    activeQuizzes: 0,
    completionRate: 0,
    totalTeachers: 0,
    totalRevenue: 0,
    newApplications: 0,
    upcomingEvents: 0,
    totalApplications: 0,
    pendingApplications: 0,
    approvedApplications: 0,
    rejectedApplications: 0,
    totalMessages: 0,
    unreadMessages: 0
  });

  // Component-specific states
  const [courses, setCourses] = useState([]);
  const [materials, setMaterials] = useState([]);
  const [quizzes, setQuizzes] = useState([]);
  const [homework, setHomework] = useState([]);
  const [students, setStudents] = useState([]);
  const [teachers, setTeachers] = useState([]);
  const [applications, setApplications] = useState([]);
  const [contactMessages, setContactMessages] = useState([]);
  const [listeningExercises, setListeningExercises] = useState([]);
  const [analyticsData, setAnalyticsData] = useState({});
  const [progressRecords, setProgressRecords] = useState([]);
  const [announcements, setAnnouncements] = useState([]);
  const [users, setUsers] = useState([]);
  const [submissions, setSubmissions] = useState([]);
  
  // Modal states
  const [applicationModalVisible, setApplicationModalVisible] = useState(false);
  const [messageModalVisible, setMessageModalVisible] = useState(false);
  const [userModalVisible, setUserModalVisible] = useState(false);
  const [createUserModalVisible, setCreateUserModalVisible] = useState(false);
  const [editUserModalVisible, setEditUserModalVisible] = useState(false);
  const [replyModalVisible, setReplyModalVisible] = useState(false);
  const [courseModalVisible, setCourseModalVisible] = useState(false);
  const [materialModalVisible, setMaterialModalVisible] = useState(false);
  const [quizModalVisible, setQuizModalVisible] = useState(false);
  const [homeworkModalVisible, setHomeworkModalVisible] = useState(false);
  const [exerciseModalVisible, setExerciseModalVisible] = useState(false);
  const [questionsModalVisible, setQuestionsModalVisible] = useState(false);
  const [submissionsModalVisible, setSubmissionsModalVisible] = useState(false);
  const [gradingModalVisible, setGradingModalVisible] = useState(false);
  const [resultsModalVisible, setResultsModalVisible] = useState(false);
  const [previewModalVisible, setPreviewModalVisible] = useState(false);
  const [progressModalVisible, setProgressModalVisible] = useState(false);
  const [announcementModalVisible, setAnnouncementModalVisible] = useState(false);
  const [viewModalVisible, setViewModalVisible] = useState(false);
  
  // Selected items
  const [selectedApplication, setSelectedApplication] = useState(null);
  const [selectedMessage, setSelectedMessage] = useState(null);
  const [selectedUser, setSelectedUser] = useState(null);
  const [selectedCourse, setSelectedCourse] = useState(null);
  const [selectedMaterial, setSelectedMaterial] = useState(null);
  const [selectedQuiz, setSelectedQuiz] = useState(null);
  const [selectedHomework, setSelectedHomework] = useState(null);
  const [selectedExercise, setSelectedExercise] = useState(null);
  const [selectedSubmission, setSelectedSubmission] = useState(null);
  const [selectedProgress, setSelectedProgress] = useState(null);
  const [selectedAnnouncement, setSelectedAnnouncement] = useState(null);
  
  // Form states
  const [editingCourse, setEditingCourse] = useState(null);
  const [editingQuiz, setEditingQuiz] = useState(null);
  const [editingHomework, setEditingHomework] = useState(null);
  const [editingExercise, setEditingExercise] = useState(null);
  const [questions, setQuestions] = useState([]);
  const [audioFile, setAudioFile] = useState(null);
  const [fileList, setFileList] = useState([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const [playingExerciseId, setPlayingExerciseId] = useState(null);
  const [replyType, setReplyType] = useState('');
  const [replyTarget, setReplyTarget] = useState(null);
  const [filterStatus, setFilterStatus] = useState('');
  const [searchTerm, setSearchTerm] = useState('');
  const [roleFilter, setRoleFilter] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [selectedFileType, setSelectedFileType] = useState('');
  
  // Forms
  const [courseForm] = Form.useForm();
  const [materialForm] = Form.useForm();
  const [quizForm] = Form.useForm();
  const [homeworkForm] = Form.useForm();
  const [exerciseForm] = Form.useForm();
  const [questionForm] = Form.useForm();
  const [replyForm] = Form.useForm();
  const [createUserForm] = Form.useForm();
  const [editUserForm] = Form.useForm();
  const [gradingForm] = Form.useForm();
  
  // Refs for audio players
  const audioRef = useRef(null);
  const tableAudioRef = useRef(null);

  // Responsive handler
  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 768);
      if (window.innerWidth < 768) {
        setCollapsed(true);
      }
    };
    
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, []);

  // Authentication check
  useEffect(() => {
    const checkAuth = () => {
      const token = localStorage.getItem('authToken') || localStorage.getItem('token');
      const userRole = localStorage.getItem('userRole');
      const userEmail = localStorage.getItem('userEmail');
      const userName = localStorage.getItem('userName');
      const userId = localStorage.getItem('userId');
      
      if (!token || !userRole) {
        history.push('/login');
        return;
      }

      if (!['superadmin', 'admin', 'faculty', 'teacher'].includes(userRole)) {
        message.error('Access denied. Admin/Faculty role required.');
        history.push('/');
        return;
      }
      
      const userData = {
        id: userId,
        email: userEmail,
        role: userRole,
        name: userName,
        firstName: userName?.split(' ')[0] || 'Admin',
        lastName: userName?.split(' ')[1] || 'User'
      };
      
      setCurrentUser(userData);
      fetchInitialData();
      setLoading(false);
    };

    checkAuth();
  }, [history]);

  // Fetch initial data
  const fetchInitialData = async () => {
    try {
      await Promise.all([
        fetchDashboardStats(),
        fetchCourses(),
        fetchStudents(),
        fetchApplications(),
        fetchContactMessages(),
        fetchUsers(),
        fetchQuizzes(),
        fetchHomework(),
        fetchMaterials(),
        fetchListeningExercises()
      ]);
    } catch (error) {
      console.error('Error fetching initial data:', error);
    }
  };

  const fetchDashboardStats = async () => {
    try {
      const token = localStorage.getItem('token');
      
      // Fetch various stats
      const [coursesRes, studentsRes, applicationsRes, messagesRes] = await Promise.all([
        fetch(`${API_BASE_URL}/api/courses`, {
          headers: { 'Authorization': `Bearer ${token}` }
        }),
        fetch(`${API_BASE_URL}/api/users?role=student`, {
          headers: { 'Authorization': `Bearer ${token}` }
        }),
        fetch(`${API_BASE_URL}/api/applications`, {
          headers: { 'Authorization': `Bearer ${token}` }
        }),
        fetch(`${API_BASE_URL}/api/contact`, {
          headers: { 'Authorization': `Bearer ${token}` }
        })
      ]);

      const coursesData = await coursesRes.json();
      const studentsData = await studentsRes.json();
      const applicationsData = await applicationsRes.json();
      const messagesData = await messagesRes.json();

      // Calculate stats
      const stats = {
        totalCourses: coursesData.courses?.length || coursesData.length || 0,
        totalStudents: studentsData.users?.length || studentsData.length || 0,
        totalApplications: applicationsData.applications?.length || applicationsData.length || 0,
        pendingApplications: (applicationsData.applications || applicationsData || []).filter(a => a.status === 'pending').length,
        approvedApplications: (applicationsData.applications || applicationsData || []).filter(a => a.status === 'approved').length,
        rejectedApplications: (applicationsData.applications || applicationsData || []).filter(a => a.status === 'rejected').length,
        totalMessages: messagesData.contacts?.length || messagesData.length || 0,
        unreadMessages: (messagesData.contacts || messagesData || []).filter(m => m.status === 'pending').length,
        completionRate: 75,
        totalMaterials: 42,
        pendingSubmissions: 8,
        activeQuizzes: 5
      };

      setDashboardStats(stats);
    } catch (error) {
      console.error('Error fetching dashboard stats:', error);
    }
  };

  const fetchCourses = async () => {
    try {
      const data = await courseAPI.getAll();
      setCourses(data.courses || data || []);
    } catch (error) {
      console.error('Error fetching courses:', error);
      setCourses([]);
    }
  };

  const fetchStudents = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`${API_BASE_URL}/api/users?role=student`, {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });
      if (response.ok) {
        const data = await response.json();
        setStudents(data.users || data || []);
      }
    } catch (error) {
      console.error('Error fetching students:', error);
      setStudents([]);
    }
  };

  const fetchApplications = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`${API_BASE_URL}/api/applications`, {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });
      if (response.ok) {
        const data = await response.json();
        setApplications(data.applications || data || []);
      }
    } catch (error) {
      console.error('Error fetching applications:', error);
      setApplications([]);
    }
  };

  const fetchContactMessages = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`${API_BASE_URL}/api/contact`, {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });
      if (response.ok) {
        const data = await response.json();
        setContactMessages(data.contacts || data || []);
      }
    } catch (error) {
      console.error('Error fetching contact messages:', error);
      setContactMessages([]);
    }
  };

  const fetchUsers = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`${API_BASE_URL}/api/users`, {
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });
      if (response.ok) {
        const data = await response.json();
        setUsers(data.users || data || []);
      }
    } catch (error) {
      console.error('Error fetching users:', error);
      setUsers([]);
    }
  };

  const fetchQuizzes = async () => {
    try {
      const data = await quizAPI.getAll();
      setQuizzes(data || []);
    } catch (error) {
      console.error('Error fetching quizzes:', error);
      setQuizzes([]);
    }
  };

  const fetchHomework = async () => {
    try {
      const data = await homeworkAPI.getAll();
      setHomework(data || []);
    } catch (error) {
      console.error('Error fetching homework:', error);
      setHomework([]);
    }
  };

  const fetchMaterials = async () => {
    try {
      const data = await materialAPI.getAll();
      setMaterials(data || []);
    } catch (error) {
      console.error('Error fetching materials:', error);
      setMaterials([]);
    }
  };

  const fetchListeningExercises = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`${API_BASE_URL}/api/listening-exercises`, {
        headers: getAuthHeaders()
      });
      if (response.ok) {
        const data = await response.json();
        setListeningExercises(data || []);
      }
    } catch (error) {
      console.error('Error fetching listening exercises:', error);
      setListeningExercises([]);
    }
  };

  const fetchQuizSubmissions = async (quizId) => {
    try {
      const data = await quizAPI.getSubmissions(quizId);
      setSubmissions(data || []);
    } catch (error) {
      console.error('Error fetching submissions:', error);
      setSubmissions([]);
    }
  };

  // Update application status
  const updateApplicationStatus = async (applicationId, status) => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`${API_BASE_URL}/api/applications/${applicationId}/status`, {
        method: 'PUT',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ status })
      });

      if (response.ok) {
        message.success(`Application ${status} successfully!`);
        fetchApplications();
        setApplicationModalVisible(false);
      } else {
        message.error('Failed to update application status');
      }
    } catch (error) {
      console.error('Error updating application status:', error);
      message.error('Error updating application status');
    }
  };

  // Update contact message status
  const updateContactStatus = async (messageId, newStatus) => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`${API_BASE_URL}/api/contact/${messageId}/status`, {
        method: 'PUT',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ status: newStatus })
      });

      if (response.ok) {
        fetchContactMessages();
        message.success(`Message marked as ${newStatus}`);
      } else {
        message.error('Failed to update contact status');
      }
    } catch (error) {
      console.error('Error updating contact status:', error);
      message.error('Error updating contact status');
    }
  };

  // Update user status
  const updateUserStatus = async (userId, isApproved, rejectionReason = '') => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`${API_BASE_URL}/api/users/${userId}/approval`, {
        method: 'PUT',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ 
          approved: isApproved,
          rejectionReason 
        })
      });

      if (response.ok) {
        const action = isApproved ? 'approved' : 'rejected';
        message.success(`User ${action} successfully`);
        fetchUsers();
      } else {
        const errorData = await response.json();
        message.error(errorData.message || 'Failed to update user status');
      }
    } catch (error) {
      console.error('Error updating user status:', error);
      message.error('Error updating user status');
    }
  };

  // Create new user
  const createUser = async (userData) => {
    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`${API_BASE_URL}/api/users`, {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(userData)
      });

      if (response.ok) {
        message.success(`${userData.role} created successfully!`);
        createUserForm.resetFields();
        setCreateUserModalVisible(false);
        fetchUsers();
      } else {
        const errorData = await response.json();
        message.error(errorData.message || 'Failed to create user');
      }
    } catch (error) {
      console.error('Error creating user:', error);
      message.error('Error creating user');
    }
  };

  // Handle course creation/update
  const handleCreateCourse = async (values) => {
    try {
      const courseData = {
        ...values,
        startDate: values.startDate?.format('YYYY-MM-DD'),
        endDate: values.endDate?.format('YYYY-MM-DD'),
        instructor: currentUser.id
      };

      if (editingCourse) {
        await courseAPI.update(editingCourse._id, courseData);
        message.success('Course updated successfully');
      } else {
        await courseAPI.create(courseData);
        message.success('Course created successfully');
      }

      setCourseModalVisible(false);
      courseForm.resetFields();
      setEditingCourse(null);
      fetchCourses();
    } catch (error) {
      console.error('Error saving course:', error);
      message.error('Error saving course');
    }
  };

  // Handle quiz creation/update
  const handleCreateQuiz = async (values) => {
    try {
      const quizData = {
        ...values,
        dueDate: values.dueDate?.format(),
        availableFrom: values.availableFrom?.format() || new Date(),
        availableTo: values.availableTo?.format(),
        createdBy: currentUser.id,
        questions: questions
      };

      if (editingQuiz) {
        await quizAPI.update(editingQuiz._id, quizData);
      } else {
        await quizAPI.create(quizData);
      }

      message.success(`Quiz ${editingQuiz ? 'updated' : 'created'} successfully`);
      setQuizModalVisible(false);
      quizForm.resetFields();
      setEditingQuiz(null);
      setQuestions([]);
      fetchQuizzes();
    } catch (error) {
      console.error('Error saving quiz:', error);
      message.error('Error saving quiz: ' + error.message);
    }
  };

  // Handle homework creation/update
  const handleCreateHomework = async (values) => {
    try {
      const homeworkData = {
        ...values,
        dueDate: values.dueDate?.format(),
        assignedDate: values.assignedDate?.format() || new Date(),
        assignedBy: currentUser.id
      };

      if (editingHomework) {
        await homeworkAPI.update(editingHomework._id, homeworkData);
      } else {
        await homeworkAPI.create(homeworkData);
      }

      message.success(`Homework ${editingHomework ? 'updated' : 'created'} successfully`);
      setHomeworkModalVisible(false);
      homeworkForm.resetFields();
      setEditingHomework(null);
      fetchHomework();
    } catch (error) {
      console.error('Error saving homework:', error);
      message.error('Failed to save homework');
    }
  };

  // Handle material upload
  const handleUploadMaterial = async (values) => {
    if (fileList.length === 0) {
      message.error('Please select a file to upload');
      return;
    }

    const formData = new FormData();
    formData.append('file', fileList[0]);
    formData.append('title', values.title);
    formData.append('description', values.description || '');
    formData.append('course', values.course);
    formData.append('category', values.category);
    formData.append('week', values.week || 1);
    formData.append('lesson', values.lesson || 1);
    formData.append('tags', JSON.stringify(values.tags || []));
    formData.append('accessLevel', values.accessLevel || 'course_students');

    try {
      await materialAPI.create(formData);
      message.success('Material uploaded successfully!');
      setMaterialModalVisible(false);
      materialForm.resetFields();
      setFileList([]);
      fetchMaterials();
    } catch (error) {
      console.error('Upload error:', error);
      message.error(error.message || 'Failed to upload material');
    }
  };

  // Handle listening exercise creation
  const handleCreateExercise = async (values) => {
    if (!audioFile) {
      message.error('Please upload an audio file');
      return;
    }

    const formData = new FormData();
    formData.append('audioFile', audioFile);
    formData.append('title', values.title);
    formData.append('description', values.description || '');
    formData.append('course', values.course);
    formData.append('level', values.level);
    formData.append('instructions', values.instructions || '');
    formData.append('transcript', values.transcript || '');
    formData.append('timeLimit', values.timeLimit || 30);
    formData.append('playLimit', values.playLimit || 3);
    formData.append('questions', JSON.stringify(questions));
    formData.append('createdBy', currentUser.id);

    try {
      const token = localStorage.getItem('token');
      const response = await fetch(`${API_BASE_URL}/api/listening-exercises`, {
        method: editingExercise ? 'PUT' : 'POST',
        headers: {
          'Authorization': `Bearer ${token}`
        },
        body: formData
      });

      if (response.ok) {
        message.success(`Exercise ${editingExercise ? 'updated' : 'created'} successfully`);
        setExerciseModalVisible(false);
        exerciseForm.resetFields();
        setEditingExercise(null);
        setAudioFile(null);
        setQuestions([]);
        fetchListeningExercises();
      } else {
        throw new Error('Failed to save exercise');
      }
    } catch (error) {
      console.error('Error saving exercise:', error);
      message.error('Error saving exercise');
    }
  };

  // Add question to quiz/exercise
  const addQuestion = () => {
    questionForm.validateFields().then(values => {
      const newQuestion = {
        id: Date.now(),
        ...values,
        options: values.type === 'multiple_choice' ? values.options || [] : []
      };
      setQuestions([...questions, newQuestion]);
      questionForm.resetFields();
      message.success('Question added successfully');
    });
  };

  const removeQuestion = (questionId) => {
    setQuestions(questions.filter(q => q.id !== questionId));
  };

  const handleLogout = () => {
    confirm({
      title: 'Confirm Logout',
      content: 'Are you sure you want to logout?',
      okText: 'Yes',
      cancelText: 'No',
      onOk() {
        localStorage.clear();
        message.success('Logged out successfully');
        history.push('/');
      }
    });
  };

  // Menu items with icons
  const menuItems = [
    {
      key: 'overview',
      icon: <DashboardOutlined />,
      label: 'Dashboard Overview'
    },
    {
      key: 'applications',
      icon: <SolutionOutlined />,
      label: 'Applications & Users'
    },
    {
      key: 'courses',
      icon: <BookOutlined />,
      label: 'Course Management'
    },
    {
      key: 'materials',
      icon: <FolderOutlined />,
      label: 'Course Materials'
    },
    {
      key: 'quizzes',
      icon: <FormOutlined />,
      label: 'Quiz Engine'
    },
    {
      key: 'homework',
      icon: <FileTextOutlined />,
      label: 'Homework System'
    },
    {
      key: 'listening',
      icon: <AudioOutlined />,
      label: 'Listening Exercises'
    },
    {
      key: 'students',
      icon: <TeamOutlined />,
      label: 'Student Progress'
    },
    {
      key: 'analytics',
      icon: <BarChartOutlined />,
      label: 'Analytics & Reports'
    },
    {
      key: 'settings',
      icon: <SettingOutlined />,
      label: 'Settings'
    }
  ];

  // Render Dashboard Overview
  const renderOverview = () => (
    <div className="dashboard-overview">
      <Row gutter={[24, 24]}>
        {/* Stats Cards */}
        <Col xs={24} sm={12} lg={6}>
          <Card className="stat-card gradient-blue" hoverable>
            <Statistic
              title={<span style={{ color: '#fff' }}>Total Courses</span>}
              value={dashboardStats.totalCourses}
              prefix={<BookOutlined style={{ color: '#fff' }} />}
              valueStyle={{ color: '#fff', fontSize: '32px' }}
            />
            <Progress 
              percent={75} 
              strokeColor="#fff" 
              trailColor="rgba(255,255,255,0.3)"
              showInfo={false}
              style={{ marginTop: 10 }}
            />
          </Card>
        </Col>
        
        <Col xs={24} sm={12} lg={6}>
          <Card className="stat-card gradient-green" hoverable>
            <Statistic
              title={<span style={{ color: '#fff' }}>Total Students</span>}
              value={dashboardStats.totalStudents}
              prefix={<UserOutlined style={{ color: '#fff' }} />}
              valueStyle={{ color: '#fff', fontSize: '32px' }}
            />
            <Progress 
              percent={85} 
              strokeColor="#fff" 
              trailColor="rgba(255,255,255,0.3)"
              showInfo={false}
              style={{ marginTop: 10 }}
            />
          </Card>
        </Col>
        
        <Col xs={24} sm={12} lg={6}>
          <Card className="stat-card gradient-orange" hoverable>
            <Statistic
              title={<span style={{ color: '#fff' }}>Pending Applications</span>}
              value={dashboardStats.pendingApplications}
              prefix={<SolutionOutlined style={{ color: '#fff' }} />}
              valueStyle={{ color: '#fff', fontSize: '32px' }}
            />
            <Progress 
              percent={dashboardStats.totalApplications > 0 ? 
                (dashboardStats.pendingApplications / dashboardStats.totalApplications) * 100 : 0} 
              strokeColor="#fff" 
              trailColor="rgba(255,255,255,0.3)"
              showInfo={false}
              style={{ marginTop: 10 }}
            />
          </Card>
        </Col>
        
        <Col xs={24} sm={12} lg={6}>
          <Card className="stat-card gradient-purple" hoverable>
            <Statistic
              title={<span style={{ color: '#fff' }}>Unread Messages</span>}
              value={dashboardStats.unreadMessages}
              prefix={<MessageOutlined style={{ color: '#fff' }} />}
              valueStyle={{ color: '#fff', fontSize: '32px' }}
            />
            <Progress 
              percent={dashboardStats.totalMessages > 0 ? 
                (dashboardStats.unreadMessages / dashboardStats.totalMessages) * 100 : 0} 
              strokeColor="#fff" 
              trailColor="rgba(255,255,255,0.3)"
              showInfo={false}
              style={{ marginTop: 10 }}
            />
          </Card>
        </Col>
      </Row>

      {/* Charts Row */}
      <Row gutter={[24, 24]} style={{ marginTop: 24 }}>
        <Col xs={24} lg={16}>
          <Card 
            title="Student Performance Trends" 
            extra={
              <Select defaultValue="week" style={{ width: 120 }}>
                <Option value="week">This Week</Option>
                <Option value="month">This Month</Option>
                <Option value="year">This Year</Option>
              </Select>
            }
          >
            <Line
              data={{
                labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
                datasets: [
                  {
                    label: 'Average Score',
                    data: [75, 78, 80, 82, 79, 85, 88],
                    borderColor: '#1890ff',
                    backgroundColor: 'rgba(24, 144, 255, 0.1)',
                    tension: 0.4
                  },
                  {
                    label: 'Completion Rate',
                    data: [65, 70, 72, 75, 73, 78, 82],
                    borderColor: '#52c41a',
                    backgroundColor: 'rgba(82, 196, 26, 0.1)',
                    tension: 0.4
                  }
                ]
              }}
              options={{
                responsive: true,
                plugins: {
                  legend: {
                    position: 'top'
                  }
                },
                scales: {
                  y: {
                    beginAtZero: true,
                    max: 100
                  }
                }
              }}
            />
          </Card>
        </Col>
        
        <Col xs={24} lg={8}>
          <Card title="Application Status">
            <Doughnut
              data={{
                labels: ['Pending', 'Approved', 'Rejected'],
                datasets: [{
                  data: [
                    dashboardStats.pendingApplications,
                    dashboardStats.approvedApplications,
                    dashboardStats.rejectedApplications
                  ],
                  backgroundColor: [
                    '#faad14',
                    '#52c41a',
                    '#f5222d'
                  ]
                }]
              }}
              options={{
                responsive: true,
                plugins: {
                  legend: {
                    position: 'bottom'
                  }
                }
              }}
            />
          </Card>
        </Col>
      </Row>

      {/* Activity and Quick Actions */}
      <Row gutter={[24, 24]} style={{ marginTop: 24 }}>
        <Col xs={24} lg={12}>
          <Card 
            title="Recent Activity" 
            extra={<Button type="link">View All</Button>}
            bodyStyle={{ padding: '12px 24px' }}
          >
            <Timeline>
              {applications.slice(0, 3).map((app, index) => (
                <Timeline.Item 
                  key={app._id || index}
                  color={app.status === 'pending' ? 'orange' : app.status === 'approved' ? 'green' : 'red'}
                  dot={<UserAddOutlined />}
                >
                  <Text strong>New application from {app.fullName}</Text>
                  <br />
                  <Text type="secondary">{app.course || app.program || 'General Application'}</Text>
                  <br />
                  <Text type="secondary" style={{ fontSize: 12 }}>
                    {moment(app.createdAt).fromNow()}
                  </Text>
                </Timeline.Item>
              ))}
              {contactMessages.slice(0, 2).map((msg, index) => (
                <Timeline.Item 
                  key={msg._id || index}
                  color="blue"
                  dot={<MessageOutlined />}
                >
                  <Text strong>Message from {msg.name}</Text>
                  <br />
                  <Text type="secondary">{msg.subject}</Text>
                  <br />
                  <Text type="secondary" style={{ fontSize: 12 }}>
                    {moment(msg.createdAt).fromNow()}
                  </Text>
                </Timeline.Item>
              ))}
            </Timeline>
          </Card>
        </Col>
        
        <Col xs={24} lg={12}>
          <Card title="Quick Actions">
            <Row gutter={[16, 16]}>
              <Col span={12}>
                <Button 
                  type="primary" 
                  icon={<SolutionOutlined />} 
                  block 
                  size="large"
                  onClick={() => setActiveKey('applications')}
                  style={{ height: 60 }}
                >
                  Review Applications
                  {dashboardStats.pendingApplications > 0 && (
                    <Badge 
                      count={dashboardStats.pendingApplications} 
                      style={{ marginLeft: 8 }}
                    />
                  )}
                </Button>
              </Col>
              <Col span={12}>
                <Button 
                  icon={<MessageOutlined />} 
                  block 
                  size="large"
                  onClick={() => setActiveKey('applications')}
                  style={{ height: 60 }}
                >
                  Check Messages
                  {dashboardStats.unreadMessages > 0 && (
                    <Badge 
                      count={dashboardStats.unreadMessages} 
                      style={{ marginLeft: 8 }}
                    />
                  )}
                </Button>
              </Col>
              <Col span={12}>
                <Button 
                  icon={<BookOutlined />} 
                  block 
                  size="large"
                  onClick={() => setActiveKey('courses')}
                  style={{ height: 60 }}
                >
                  Manage Courses
                </Button>
              </Col>
              <Col span={12}>
                <Button 
                  icon={<TeamOutlined />} 
                  block 
                  size="large"
                  onClick={() => setActiveKey('students')}
                  style={{ height: 60 }}
                >
                  Student Progress
                </Button>
              </Col>
            </Row>
          </Card>
        </Col>
      </Row>
    </div>
  );

  // Render Applications & Users Management
  const renderApplicationsManagement = () => {
    const applicationColumns = [
      {
        title: 'Name',
        dataIndex: 'fullName',
        key: 'fullName',
        render: (name, record) => (
          <div>
            <Text strong>{name}</Text>
            <br />
            <Text type="secondary" style={{ fontSize: '12px' }}>
              {record.email}
            </Text>
          </div>
        )
      },
      {
        title: 'Program',
        dataIndex: 'course',
        key: 'course',
        render: (course, record) => (
          <Tag color="blue">{course || record.program || 'Not specified'}</Tag>
        )
      },
      {
        title: 'Status',
        dataIndex: 'status',
        key: 'status',
        render: (status) => {
          const colors = {
            pending: 'orange',
            approved: 'green',
            rejected: 'red'
          };
          return <Tag color={colors[status]}>{status?.toUpperCase()}</Tag>;
        }
      },
      {
        title: 'Applied Date',
        dataIndex: 'createdAt',
        key: 'createdAt',
        render: (date) => moment(date).format('MMM DD, YYYY')
      },
      {
        title: 'Actions',
        key: 'actions',
        width: 250,
        render: (_, record) => (
          <Space>
            <Button
              icon={<EyeOutlined />}
              size="small"
              onClick={() => {
                setSelectedApplication(record);
                setApplicationModalVisible(true);
              }}
            >
              View
            </Button>
            {record.status === 'pending' && (
              <>
                <Button
                  icon={<CheckOutlined />}
                  size="small"
                  type="primary"
                  style={{ backgroundColor: '#52c41a', borderColor: '#52c41a' }}
                  onClick={() => updateApplicationStatus(record._id, 'approved')}
                >
                  Approve
                </Button>
                <Button
                  icon={<CloseOutlined />}
                  size="small"
                  danger
                  onClick={() => updateApplicationStatus(record._id, 'rejected')}
                >
                  Reject
                </Button>
              </>
            )}
          </Space>
        )
      }
    ];

    const messageColumns = [
      {
        title: 'Contact Info',
        key: 'contact',
        render: (_, record) => (
          <div>
            <Text strong>{record.name}</Text>
            <br />
            <Text type="secondary" style={{ fontSize: '12px' }}>
              {record.email}
            </Text>
          </div>
        )
      },
      {
        title: 'Subject',
        dataIndex: 'subject',
        key: 'subject',
        render: (subject) => (
          <Text ellipsis style={{ maxWidth: 200 }}>{subject}</Text>
        )
      },
      {
        title: 'Status',
        dataIndex: 'status',
        key: 'status',
        render: (status) => {
          const statusConfig = {
            pending: { color: 'orange', text: 'Pending' },
            resolved: { color: 'green', text: 'Resolved' },
            approved: { color: 'blue', text: 'Approved' },
            ignored: { color: 'red', text: 'Ignored' }
          };
          const config = statusConfig[status] || { color: 'default', text: status || 'Unknown' };
          return <Tag color={config.color}>{config.text}</Tag>;
        }
      },
      {
        title: 'Received',
        dataIndex: 'createdAt',
        key: 'createdAt',
        render: (date) => moment(date).format('MMM DD, YYYY')
      },
      {
        title: 'Actions',
        key: 'actions',
        render: (_, record) => (
          <Space>
            <Button
              icon={<EyeOutlined />}
              size="small"
              onClick={() => {
                setSelectedMessage(record);
                setMessageModalVisible(true);
                if (record.status === 'pending') {
                  updateContactStatus(record._id, 'resolved');
                }
              }}
            >
              View
            </Button>
            {record.status === 'pending' && (
              <Button
                icon={<CheckOutlined />}
                size="small"
                type="primary"
                onClick={() => updateContactStatus(record._id, 'resolved')}
              >
                Mark Resolved
              </Button>
            )}
          </Space>
        )
      }
    ];

    const userColumns = [
      {
        title: 'User Info',
        key: 'userInfo',
        render: (_, record) => (
          <div>
            <Text strong>{record.firstName} {record.lastName}</Text>
            <br />
            <Text type="secondary" style={{ fontSize: '12px' }}>
              {record.email}
            </Text>
          </div>
        )
      },
      {
        title: 'Role',
        dataIndex: 'role',
        key: 'role',
        render: (role) => (
          <Tag color={role === 'teacher' ? 'blue' : role === 'student' ? 'green' : 'default'}>
            {role?.toUpperCase()}
          </Tag>
        )
      },
      {
        title: 'Status',
        dataIndex: 'isApproved',
        key: 'isApproved',
        render: (isApproved) => {
          if (isApproved === true) {
            return <Tag color="green" icon={<CheckCircleOutlined />}>Approved</Tag>;
          } else if (isApproved === false) {
            return <Tag color="red" icon={<CloseCircleOutlined />}>Rejected</Tag>;
          } else {
            return <Tag color="orange">Pending</Tag>;
          }
        }
      },
      {
        title: 'Registration Date',
        dataIndex: 'createdAt',
        key: 'createdAt',
        render: (date) => moment(date).format('MMM DD, YYYY')
      },
      {
        title: 'Actions',
        key: 'actions',
        render: (_, record) => (
          <Space>
            <Button
              icon={<EyeOutlined />}
              size="small"
              onClick={() => {
                setSelectedUser(record);
                setUserModalVisible(true);
              }}
            >
              View
            </Button>
            {record.isApproved !== true && (
              <Button
                icon={<CheckOutlined />}
                size="small"
                type="primary"
                style={{ backgroundColor: '#52c41a', borderColor: '#52c41a' }}
                onClick={() => updateUserStatus(record._id, true)}
              >
                Approve
              </Button>
            )}
            {record.isApproved !== false && (
              <Button
                icon={<CloseOutlined />}
                size="small"
                danger
                onClick={() => updateUserStatus(record._id, false)}
              >
                Reject
              </Button>
            )}
          </Space>
        )
      }
    ];

    const filteredApplications = applications.filter(app => {
      const matchesStatus = !filterStatus || app.status === filterStatus;
      const matchesSearch = !searchTerm || 
        app.fullName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        app.email?.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesStatus && matchesSearch;
    });

    const filteredMessages = contactMessages.filter(msg => {
      const matchesSearch = !searchTerm || 
        msg.name?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        msg.email?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        msg.subject?.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesSearch;
    });

    const filteredUsers = users.filter(user => {
      const matchesSearch = !searchTerm || 
        user.firstName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        user.lastName?.toLowerCase().includes(searchTerm.toLowerCase()) ||
        user.email?.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesRole = !roleFilter || user.role === roleFilter;
      return matchesSearch && matchesRole;
    });

    return (
      <div>
        <Title level={2}>📋 Application Management</Title>
        <Text type="secondary">Manage student applications, contact messages, and user registrations</Text>

        {/* Statistics Cards */}
        <Row gutter={[16, 16]} style={{ marginTop: '24px', marginBottom: '24px' }}>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Total Applications"
                value={dashboardStats.totalApplications}
                prefix={<UserOutlined />}
                valueStyle={{ color: '#1890ff' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Pending Review"
                value={dashboardStats.pendingApplications}
                prefix={<CalendarOutlined />}
                valueStyle={{ color: '#faad14' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Contact Messages"
                value={dashboardStats.totalMessages}
                prefix={<MessageOutlined />}
                valueStyle={{ color: '#52c41a' }}
              />
            </Card>
          </Col>
          <Col xs={24} sm={12} md={6}>
            <Card>
              <Statistic
                title="Pending Users"
                value={users.filter(user => user.isApproved !== true && user.isApproved !== false).length}
                prefix={<UserOutlined />}
                valueStyle={{ color: '#f5222d' }}
              />
            </Card>
          </Col>
        </Row>

        {/* Tabs for different management sections */}
        <Tabs
          defaultActiveKey="applications"
          items={[
            {
              key: 'applications',
              label: '📝 Applications',
              children: (
                <Card 
                  title="Student Applications" 
                  extra={
                    <Space>
                      <Input
                        placeholder="Search applications..."
                        prefix={<SearchOutlined />}
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        style={{ width: 200 }}
                      />
                      <Select
                        placeholder="Filter by status"
                        value={filterStatus}
                        onChange={setFilterStatus}
                        style={{ width: 150 }}
                        allowClear
                      >
                        <Select.Option value="pending">Pending</Select.Option>
                        <Select.Option value="approved">Approved</Select.Option>
                        <Select.Option value="rejected">Rejected</Select.Option>
                      </Select>
                    </Space>
                  }
                >
                  <Table
                    columns={applicationColumns}
                    dataSource={filteredApplications}
                    rowKey="_id"
                    pagination={{
                      pageSize: 10,
                      showSizeChanger: true,
                      showQuickJumper: true,
                    }}
                  />
                </Card>
              )
            },
            {
              key: 'contacts',
              label: '💬 Messages',
              children: (
                <Card 
                  title="Contact Messages"
                  extra={
                    <Space>
                      <Input
                        placeholder="Search messages..."
                        prefix={<SearchOutlined />}
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        style={{ width: 200 }}
                      />
                      <Button icon={<DownloadOutlined />} type="primary">
                        Export Messages
                      </Button>
                    </Space>
                  }
                >
                  <Table
                    columns={messageColumns}
                    dataSource={filteredMessages}
                    rowKey="_id"
                    pagination={{
                      pageSize: 10,
                      showSizeChanger: true,
                      showQuickJumper: true,
                    }}
                  />
                </Card>
              )
            },
            {
              key: 'users',
              label: '👥 Users',
              children: (
                <Card 
                  title="User Registrations"
                  extra={
                    <Space>
                      <Input
                        placeholder="Search users..."
                        prefix={<SearchOutlined />}
                        value={searchTerm}
                        onChange={(e) => setSearchTerm(e.target.value)}
                        style={{ width: 200 }}
                      />
                      <Select
                        placeholder="Filter by role"
                        value={roleFilter}
                        onChange={(value) => setRoleFilter(value)}
                        style={{ width: 150 }}
                        allowClear
                      >
                        <Select.Option value="teacher">Teacher</Select.Option>
                        <Select.Option value="student">Student</Select.Option>
                        <Select.Option value="admin">Admin</Select.Option>
                      </Select>
                      <Button 
                        type="primary" 
                        icon={<UserOutlined />}
                        onClick={() => setCreateUserModalVisible(true)}
                      >
                        Create User
                      </Button>
                    </Space>
                  }
                >
                  <Table
                    columns={userColumns}
                    dataSource={filteredUsers}
                    rowKey="_id"
                    pagination={{
                      pageSize: 10,
                      showSizeChanger: true,
                      showQuickJumper: true,
                    }}
                  />
                </Card>
              )
            }
          ]}
        />
      </div>
    );
  };

  // Main content renderer
  const renderContent = () => {
    switch(activeKey) {
      case 'overview':
        return renderOverview();
      case 'applications':
        return renderApplicationsManagement();
      case 'courses':
        // Course management implementation here
        return <Card title="Course Management">Course management functionality</Card>;
      case 'materials':
        // Material management implementation here
        return <Card title="Material Management">Material management functionality</Card>;
      case 'quizzes':
        // Quiz management implementation here
        return <Card title="Quiz Management">Quiz management functionality</Card>;
      case 'homework':
        // Homework management implementation here
        return <Card title="Homework Management">Homework management functionality</Card>;
      case 'listening':
        // Listening exercises implementation here
        return <Card title="Listening Exercises">Listening exercises functionality</Card>;
      case 'students':
        // Student progress implementation here
        return <Card title="Student Progress">Student progress functionality</Card>;
      case 'analytics':
        // Analytics implementation here
        return <Card title="Analytics & Reports">Analytics functionality</Card>;
      case 'settings':
        // Settings implementation here
        return <Card title="Settings">Settings functionality</Card>;
      default:
        return renderOverview();
    }
  };

  if (loading) {
    return (
      <div style={{ 
        display: 'flex', 
        justifyContent: 'center', 
        alignItems: 'center', 
        height: '100vh',
        background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)'
      }}>
        <Spin size="large" tip="Loading Dashboard..." />
      </div>
    );
  }

  return (
    <Layout style={{ minHeight: '100vh' }}>
      {/* Modern Sidebar */}
      <Sider 
        trigger={null} 
        collapsible 
        collapsed={collapsed}
        breakpoint="lg"
        onBreakpoint={(broken) => {
          setCollapsed(broken);
        }}
        width={260}
        className="modern-sidebar"
        style={{
          background: 'linear-gradient(180deg, #667eea 0%, #764ba2 50%, #f093fb 100%)',
          position: 'fixed',
          height: '100vh',
          left: 0,
          top: 0,
          bottom: 0,
          zIndex: 1000,
          boxShadow: '4px 0 30px rgba(102, 126, 234, 0.4)',
          overflow: 'auto'
        }}
      >
        {/* Logo Section */}
        <div className="sidebar-logo-section" style={{
          padding: '30px 20px',
          textAlign: 'center',
          borderBottom: '2px solid rgba(255, 255, 255, 0.2)',
          background: 'rgba(255, 255, 255, 0.1)'
        }}>
          <div className="logo-container">
            <div className="logo-icon-box" style={{
              width: 70,
              height: 70,
              margin: '0 auto',
              background: 'linear-gradient(135deg, #ff6b6b 0%, #ee5a52 100%)',
              borderRadius: 20,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              boxShadow: '0 10px 30px rgba(255, 107, 107, 0.4)',
              marginBottom: 15
            }}>
              <RocketOutlined style={{ fontSize: 35, color: '#fff' }} />
            </div>
            {!collapsed && (
              <div>
                <Title level={3} style={{ color: '#fff', margin: 0 }}>
                  Forum Academy
                </Title>
                <Badge 
                  count="ADMIN PORTAL" 
                  style={{ 
                    backgroundColor: '#52c41a',
                    color: '#fff',
                    marginTop: 8
                  }} 
                />
              </div>
            )}
          </div>
        </div>
        
        {/* Navigation Menu */}
        <Menu
          theme="dark"
          mode="inline"
          selectedKeys={[activeKey]}
          onClick={(e) => setActiveKey(e.key)}
          style={{ 
            background: 'transparent',
            borderRight: 0,
            padding: '20px 10px'
          }}
          items={menuItems.map(item => ({
            ...item,
            style: {
              margin: '8px 0',
              borderRadius: '12px'
            }
          }))}
        />
      </Sider>

      {/* Main Layout */}
      <Layout style={{ marginLeft: collapsed ? 80 : 260, transition: 'all 0.3s' }}>
        {/* Header */}
        <Header style={{ 
          padding: '0 24px', 
          background: '#fff',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          boxShadow: '0 2px 8px rgba(0,0,0,0.1)',
          position: 'sticky',
          top: 0,
          zIndex: 999
        }}>
          <div style={{ display: 'flex', alignItems: 'center' }}>
            <Button
              type="text"
              icon={collapsed ? <MenuUnfoldOutlined /> : <MenuFoldOutlined />}
              onClick={() => setCollapsed(!collapsed)}
              style={{
                fontSize: '16px',
                width: 64,
                height: 64,
              }}
            />
            <Breadcrumb style={{ marginLeft: 16 }}>
              <Breadcrumb.Item>
                <HomeOutlined />
              </Breadcrumb.Item>
              <Breadcrumb.Item>Dashboard</Breadcrumb.Item>
              <Breadcrumb.Item>{menuItems.find(item => item.key === activeKey)?.label}</Breadcrumb.Item>
            </Breadcrumb>
          </div>
          
          <div style={{ display: 'flex', alignItems: 'center', gap: 16 }}>
            {/* Notifications */}
            <Badge count={5}>
              <Button
                type="text"
                icon={<BellOutlined />}
                style={{ fontSize: 18 }}
              />
            </Badge>
            
            {/* User Profile Dropdown */}
            <Dropdown
              menu={{
                items: [
                  {
                    key: 'profile',
                    icon: <UserOutlined />,
                    label: 'Profile',
                    onClick: () => message.info('Profile page coming soon')
                  },
                  {
                    key: 'settings',
                    icon: <SettingOutlined />,
                    label: 'Settings',
                    onClick: () => setActiveKey('settings')
                  },
                  {
                    type: 'divider'
                  },
                  {
                    key: 'logout',
                    icon: <LogoutOutlined />,
                    label: 'Logout',
                    onClick: handleLogout
                  }
                ]
              }}
              placement="bottomRight"
            >
              <div style={{ 
                display: 'flex', 
                alignItems: 'center', 
                cursor: 'pointer',
                padding: '4px 12px',
                borderRadius: 8,
                transition: 'background 0.3s',
                '&:hover': {
                  background: '#f0f0f0'
                }
              }}>
                <Avatar 
                  style={{ 
                    backgroundColor: '#1890ff',
                    marginRight: 8 
                  }}
                  icon={<UserOutlined />}
                />
                <div>
                  <Text strong>{currentUser?.firstName} {currentUser?.lastName}</Text>
                  <br />
                  <Text type="secondary" style={{ fontSize: 12 }}>
                    {currentUser?.role?.toUpperCase()}
                  </Text>
                </div>
              </div>
            </Dropdown>
          </div>
        </Header>

        {/* Content */}
        <Content style={{ 
          margin: '24px',
          minHeight: 280,
          background: '#f0f2f5'
        }}>
          {renderContent()}
        </Content>

        {/* Footer */}
        <Layout.Footer style={{ 
          textAlign: 'center',
          background: '#fff',
          borderTop: '1px solid #f0f0f0'
        }}>
          <Text type="secondary">
            Forum Academy Admin Dashboard ©{new Date().getFullYear()} | 
            <span style={{ marginLeft: 8 }}>
              Made with <HeartOutlined style={{ color: '#ff4d4f' }} /> by Forum Academy Team
            </span>
          </Text>
        </Layout.Footer>
      </Layout>

      {/* Modals */}
      
      {/* Application Details Modal */}
      <Modal
        title="Application Details"
        visible={applicationModalVisible}
        onCancel={() => setApplicationModalVisible(false)}
        width={800}
        footer={[
          <Button key="close" onClick={() => setApplicationModalVisible(false)}>
            Close
          </Button>,
          selectedApplication?.status === 'pending' && (
            <>
              <Button
                key="reject"
                danger
                onClick={() => updateApplicationStatus(selectedApplication._id, 'rejected')}
              >
                Reject
              </Button>
              <Button
                key="approve"
                type="primary"
                onClick={() => updateApplicationStatus(selectedApplication._id, 'approved')}
              >
                Approve
              </Button>
            </>
          )
        ]}
      >
        {selectedApplication && (
          <Descriptions bordered column={2}>
            <Descriptions.Item label="Full Name" span={2}>
              {selectedApplication.fullName}
            </Descriptions.Item>
            <Descriptions.Item label="Email">
              {selectedApplication.email}
            </Descriptions.Item>
            <Descriptions.Item label="Phone">
              {selectedApplication.phone}
            </Descriptions.Item>
            <Descriptions.Item label="Program">
              {selectedApplication.course || selectedApplication.program}
            </Descriptions.Item>
            <Descriptions.Item label="Status">
              <Tag color={
                selectedApplication.status === 'pending' ? 'orange' :
                selectedApplication.status === 'approved' ? 'green' : 'red'
              }>
                {selectedApplication.status?.toUpperCase()}
              </Tag>
            </Descriptions.Item>
            <Descriptions.Item label="Applied Date">
              {moment(selectedApplication.createdAt).format('MMMM DD, YYYY')}
            </Descriptions.Item>
            <Descriptions.Item label="Education Level">
              {selectedApplication.educationLevel || 'Not specified'}
            </Descriptions.Item>
            <Descriptions.Item label="Message" span={2}>
              {selectedApplication.message || 'No message provided'}
            </Descriptions.Item>
          </Descriptions>
        )}
      </Modal>

      {/* Message Details Modal */}
      <Modal
        title="Message Details"
        visible={messageModalVisible}
        onCancel={() => setMessageModalVisible(false)}
        width={700}
        footer={[
          <Button key="close" onClick={() => setMessageModalVisible(false)}>
            Close
          </Button>,
          <Button
            key="reply"
            type="primary"
            icon={<MailOutlined />}
            onClick={() => {
              setReplyType('message');
              setReplyTarget(selectedMessage);
              setReplyModalVisible(true);
            }}
          >
            Reply
          </Button>
        ]}
      >
        {selectedMessage && (
          <Descriptions bordered column={1}>
            <Descriptions.Item label="From">
              {selectedMessage.name} ({selectedMessage.email})
            </Descriptions.Item>
            <Descriptions.Item label="Phone">
              {selectedMessage.phone || 'Not provided'}
            </Descriptions.Item>
            <Descriptions.Item label="Subject">
              {selectedMessage.subject}
            </Descriptions.Item>
            <Descriptions.Item label="Message">
              <Paragraph>{selectedMessage.message}</Paragraph>
            </Descriptions.Item>
            <Descriptions.Item label="Received">
              {moment(selectedMessage.createdAt).format('MMMM DD, YYYY HH:mm')}
            </Descriptions.Item>
            <Descriptions.Item label="Status">
              <Tag color={selectedMessage.status === 'pending' ? 'orange' : 'green'}>
                {selectedMessage.status?.toUpperCase()}
              </Tag>
            </Descriptions.Item>
          </Descriptions>
        )}
      </Modal>

      {/* User Details Modal */}
      <Modal
        title="User Details"
        visible={userModalVisible}
        onCancel={() => setUserModalVisible(false)}
        width={700}
        footer={[
          <Button key="close" onClick={() => setUserModalVisible(false)}>
            Close
          </Button>,
          selectedUser?.isApproved !== true && (
            <Button
              key="approve"
              type="primary"
              onClick={() => updateUserStatus(selectedUser._id, true)}
            >
              Approve User
            </Button>
          ),
          selectedUser?.isApproved !== false && (
            <Button
              key="reject"
              danger
              onClick={() => updateUserStatus(selectedUser._id, false)}
            >
              Reject User
            </Button>
          )
        ]}
      >
        {selectedUser && (
          <Descriptions bordered column={2}>
            <Descriptions.Item label="Name" span={2}>
              {selectedUser.firstName} {selectedUser.lastName}
            </Descriptions.Item>
            <Descriptions.Item label="Email">
              {selectedUser.email}
            </Descriptions.Item>
            <Descriptions.Item label="Role">
              <Tag color={selectedUser.role === 'teacher' ? 'blue' : 'green'}>
                {selectedUser.role?.toUpperCase()}
              </Tag>
            </Descriptions.Item>
            <Descriptions.Item label="Status">
              {selectedUser.isApproved === true ? (
                <Tag color="green" icon={<CheckCircleOutlined />}>Approved</Tag>
              ) : selectedUser.isApproved === false ? (
                <Tag color="red" icon={<CloseCircleOutlined />}>Rejected</Tag>
              ) : (
                <Tag color="orange">Pending</Tag>
              )}
            </Descriptions.Item>
            <Descriptions.Item label="Registered">
              {moment(selectedUser.createdAt).format('MMMM DD, YYYY')}
            </Descriptions.Item>
            {selectedUser.phone && (
              <Descriptions.Item label="Phone" span={2}>
                {selectedUser.phone}
              </Descriptions.Item>
            )}
            {selectedUser.bio && (
              <Descriptions.Item label="Bio" span={2}>
                {selectedUser.bio}
              </Descriptions.Item>
            )}
          </Descriptions>
        )}
      </Modal>

      {/* Create User Modal */}
      <Modal
        title="Create New User"
        visible={createUserModalVisible}
        onCancel={() => {
          setCreateUserModalVisible(false);
          createUserForm.resetFields();
        }}
        onOk={() => createUserForm.submit()}
        width={600}
      >
        <Form
          form={createUserForm}
          layout="vertical"
          onFinish={createUser}
        >
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="firstName"
                label="First Name"
                rules={[{ required: true, message: 'Please enter first name' }]}
              >
                <Input placeholder="Enter first name" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="lastName"
                label="Last Name"
                rules={[{ required: true, message: 'Please enter last name' }]}
              >
                <Input placeholder="Enter last name" />
              </Form.Item>
            </Col>
          </Row>
          
          <Form.Item
            name="email"
            label="Email"
            rules={[
              { required: true, message: 'Please enter email' },
              { type: 'email', message: 'Please enter a valid email' }
            ]}
          >
            <Input placeholder="Enter email address" />
          </Form.Item>
          
          <Form.Item
            name="password"
            label="Password"
            rules={[
              { required: true, message: 'Please enter password' },
              { min: 6, message: 'Password must be at least 6 characters' }
            ]}
          >
            <Input.Password placeholder="Enter password" />
          </Form.Item>
          
          <Form.Item
            name="role"
            label="Role"
            rules={[{ required: true, message: 'Please select a role' }]}
          >
            <Select placeholder="Select user role">
              <Option value="student">Student</Option>
              <Option value="teacher">Teacher</Option>
              <Option value="admin">Admin</Option>
            </Select>
          </Form.Item>
          
          <Form.Item
            name="phone"
            label="Phone Number"
          >
            <Input placeholder="Enter phone number (optional)" />
          </Form.Item>
          
          <Form.Item
            name="isApproved"
            label="Approval Status"
            valuePropName="checked"
          >
            <Switch checkedChildren="Approved" unCheckedChildren="Pending" />
          </Form.Item>
        </Form>
      </Modal>

      {/* Reply Modal */}
      <Modal
        title={`Reply to ${replyTarget?.name || replyTarget?.fullName || 'User'}`}
        visible={replyModalVisible}
        onCancel={() => {
          setReplyModalVisible(false);
          replyForm.resetFields();
        }}
        onOk={() => replyForm.submit()}
        width={600}
      >
        <Form
          form={replyForm}
          layout="vertical"
          onFinish={(values) => {
            message.success('Reply sent successfully!');
            setReplyModalVisible(false);
            replyForm.resetFields();
          }}
        >
          <Form.Item
            name="subject"
            label="Subject"
            rules={[{ required: true, message: 'Please enter subject' }]}
            initialValue={replyTarget?.subject ? `Re: ${replyTarget.subject}` : ''}
          >
            <Input placeholder="Enter email subject" />
          </Form.Item>
          
          <Form.Item
            name="message"
            label="Message"
            rules={[{ required: true, message: 'Please enter your message' }]}
          >
            <TextArea 
              rows={6} 
              placeholder="Type your reply message here..."
            />
          </Form.Item>
          
          <Form.Item
            name="attachments"
            label="Attachments (Optional)"
          >
            <Upload>
              <Button icon={<UploadOutlined />}>Attach Files</Button>
            </Upload>
          </Form.Item>
        </Form>
      </Modal>

      {/* Course Modal */}
      <Modal
        title={editingCourse ? 'Edit Course' : 'Create New Course'}
        visible={courseModalVisible}
        onCancel={() => {
          setCourseModalVisible(false);
          courseForm.resetFields();
          setEditingCourse(null);
        }}
        onOk={() => courseForm.submit()}
        width={800}
      >
        <Form
          form={courseForm}
          layout="vertical"
          onFinish={handleCreateCourse}
          initialValues={editingCourse}
        >
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="title"
                label="Course Title"
                rules={[{ required: true, message: 'Please enter course title' }]}
              >
                <Input placeholder="Enter course title" />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="code"
                label="Course Code"
                rules={[{ required: true, message: 'Please enter course code' }]}
              >
                <Input placeholder="e.g., CS101" />
              </Form.Item>
            </Col>
          </Row>
          
          <Form.Item
            name="description"
            label="Description"
            rules={[{ required: true, message: 'Please enter course description' }]}
          >
            <TextArea rows={4} placeholder="Enter course description" />
          </Form.Item>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="category"
                label="Category"
                rules={[{ required: true, message: 'Please select category' }]}
              >
                <Select placeholder="Select category">
                  <Option value="programming">Programming</Option>
                  <Option value="design">Design</Option>
                  <Option value="business">Business</Option>
                  <Option value="language">Language</Option>
                  <Option value="science">Science</Option>
                </Select>
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="level"
                label="Level"
                rules={[{ required: true, message: 'Please select level' }]}
              >
                <Select placeholder="Select level">
                  <Option value="beginner">Beginner</Option>
                  <Option value="intermediate">Intermediate</Option>
                  <Option value="advanced">Advanced</Option>
                </Select>
              </Form.Item>
            </Col>
          </Row>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="startDate"
                label="Start Date"
                rules={[{ required: true, message: 'Please select start date' }]}
              >
                <DatePicker style={{ width: '100%' }} />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="endDate"
                label="End Date"
                rules={[{ required: true, message: 'Please select end date' }]}
              >
                <DatePicker style={{ width: '100%' }} />
              </Form.Item>
            </Col>
          </Row>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="capacity"
                label="Maximum Students"
                rules={[{ required: true, message: 'Please enter capacity' }]}
              >
                <InputNumber min={1} max={500} style={{ width: '100%' }} />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="price"
                label="Price ($)"
                rules={[{ required: true, message: 'Please enter price' }]}
              >
                <InputNumber min={0} style={{ width: '100%' }} />
              </Form.Item>
            </Col>
          </Row>
        </Form>
      </Modal>

      {/* Material Upload Modal */}
      <Modal
        title="Upload Course Material"
        visible={materialModalVisible}
        onCancel={() => {
          setMaterialModalVisible(false);
          materialForm.resetFields();
          setFileList([]);
        }}
        onOk={() => materialForm.submit()}
        width={700}
      >
        <Form
          form={materialForm}
          layout="vertical"
          onFinish={handleUploadMaterial}
        >
          <Form.Item
            name="title"
            label="Material Title"
            rules={[{ required: true, message: 'Please enter material title' }]}
          >
            <Input placeholder="Enter material title" />
          </Form.Item>
          
          <Form.Item
            name="description"
            label="Description"
          >
            <TextArea rows={3} placeholder="Enter material description (optional)" />
          </Form.Item>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="course"
                label="Course"
                rules={[{ required: true, message: 'Please select course' }]}
              >
                <Select placeholder="Select course">
                  {courses.map(course => (
                    <Option key={course._id} value={course._id}>
                      {course.title}
                    </Option>
                  ))}
                </Select>
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="category"
                label="Category"
                rules={[{ required: true, message: 'Please select category' }]}
              >
                <Select placeholder="Select category">
                  <Option value="lecture">Lecture</Option>
                  <Option value="assignment">Assignment</Option>
                  <Option value="resource">Resource</Option>
                  <Option value="video">Video</Option>
                  <Option value="document">Document</Option>
                </Select>
              </Form.Item>
            </Col>
          </Row>
          
          <Form.Item
            label="Upload File"
            rules={[{ required: true, message: 'Please upload a file' }]}
          >
            <Dragger
              fileList={fileList}
              beforeUpload={(file) => {
                setFileList([file]);
                return false;
              }}
              onRemove={() => setFileList([])}
              maxCount={1}
            >
              <p className="ant-upload-drag-icon">
                <InboxOutlined />
              </p>
              <p className="ant-upload-text">Click or drag file to this area to upload</p>
              <p className="ant-upload-hint">
                Support for PDF, DOC, DOCX, PPT, PPTX, XLS, XLSX, ZIP, RAR
              </p>
            </Dragger>
          </Form.Item>
          
          <Row gutter={16}>
            <Col span={12}>
              <Form.Item
                name="week"
                label="Week Number"
              >
                <InputNumber min={1} max={52} style={{ width: '100%' }} />
              </Form.Item>
            </Col>
            <Col span={12}>
              <Form.Item
                name="accessLevel"
                label="Access Level"
              >
                <Select defaultValue="course_students">
                  <Option value="public">Public</Option>
                  <Option value="course_students">Course Students Only</Option>
                  <Option value="premium">Premium Members</Option>
                </Select>
              </Form.Item>
            </Col>
          </Row>
        </Form>
      </Modal>

      {/* Quiz Modal */}
      <Modal
        title={editingQuiz ? 'Edit Quiz' : 'Create New Quiz'}
        visible={quizModalVisible}
        onCancel={() => {
          setQuizModalVisible(false);
          quizForm.resetFields();
          setEditingQuiz(null);
          setQuestions([]);
        }}
        footer={null}
        width={900}
      >
        <Form
          form={quizForm}
          layout="vertical"
          onFinish={handleCreateQuiz}
        >
          <Tabs defaultActiveKey="basic">
            <TabPane tab="Basic Information" key="basic">
              <Row gutter={16}>
                <Col span={12}>
                  <Form.Item
                    name="title"
                    label="Quiz Title"
                    rules={[{ required: true, message: 'Please enter quiz title' }]}
                  >
                    <Input placeholder="Enter quiz title" />
                  </Form.Item>
                </Col>
                <Col span={12}>
                  <Form.Item
                    name="course"
                    label="Course"
                    rules={[{ required: true, message: 'Please select course' }]}
                  >
                    <Select placeholder="Select course">
                      {courses.map(course => (
                        <Option key={course._id} value={course._id}>
                          {course.title}
                        </Option>
                      ))}
                    </Select>
                  </Form.Item>
                </Col>
              </Row>
              
              <Form.Item
                name="description"
                label="Description"
              >
                <TextArea rows={3} placeholder="Enter quiz description" />
              </Form.Item>
              
              <Row gutter={16}>
                <Col span={8}>
                  <Form.Item
                    name="duration"
                    label="Duration (minutes)"
                    rules={[{ required: true, message: 'Please enter duration' }]}
                  >
                    <InputNumber min={1} max={300} style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
                <Col span={8}>
                  <Form.Item
                    name="passingScore"
                    label="Passing Score (%)"
                    rules={[{ required: true, message: 'Please enter passing score' }]}
                  >
                    <InputNumber min={0} max={100} style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
                <Col span={8}>
                  <Form.Item
                    name="attempts"
                    label="Max Attempts"
                  >
                    <InputNumber min={1} max={10} style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
              </Row>
              
              <Row gutter={16}>
                <Col span={12}>
                  <Form.Item
                    name="availableFrom"
                    label="Available From"
                  >
                    <DatePicker showTime style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
                <Col span={12}>
                  <Form.Item
                    name="availableTo"
                    label="Available Until"
                  >
                    <DatePicker showTime style={{ width: '100%' }} />
                  </Form.Item>
                </Col>
              </Row>
            </TabPane>
            
            <TabPane tab={`Questions (${questions.length})`} key="questions">
              <Button
                type="dashed"
                icon={<PlusOutlined />}
                onClick={() => setQuestionsModalVisible(true)}
                style={{ width: '100%', marginBottom: 16 }}
              >
                Add Question
              </Button>
              
              {questions.length > 0 ? (
                <List
                  dataSource={questions}
                  renderItem={(question, index) => (
                    <List.Item
                      actions={[
                        <Button
                          icon={<EditOutlined />}
                          size="small"
                          onClick={() => message.info('Edit functionality coming soon')}
                        />,
                        <Button
                          icon={<DeleteOutlined />}
                          size="small"
                          danger
                          onClick={() => removeQuestion(question.id)}
                        />
                      ]}
                    >
                      <List.Item.Meta
                        avatar={<Avatar>{index + 1}</Avatar>}
                        title={question.question}
                        description={
                          <div>
                            <Tag color="blue">{question.type}</Tag>
                            <Tag color="green">Points: {question.points || 1}</Tag>
                            {question.type === 'multiple_choice' && (
                              <div style={{ marginTop: 8 }}>
                                Options: {question.options?.join(', ')}
                              </div>
                            )}
                          </div>
                        }
                      />
                    </List.Item>
                  )}
                />
              ) : (
                <Empty description="No questions added yet" />
              )}
            </TabPane>
          </Tabs>
          
          <div style={{ marginTop: 24, textAlign: 'right' }}>
            <Space>
              <Button onClick={() => {
                setQuizModalVisible(false);
                quizForm.resetFields();
                setQuestions([]);
              }}>
                Cancel
              </Button>
              <Button type="primary" htmlType="submit">
                {editingQuiz ? 'Update Quiz' : 'Create Quiz'}
              </Button>
            </Space>
          </div>
        </Form>
      </Modal>

      {/* Add Question Modal */}
      <Modal
        title="Add Question"
        visible={questionsModalVisible}
        onCancel={() => {
          setQuestionsModalVisible(false);
          questionForm.resetFields();
        }}
        onOk={() => {
          addQuestion();
          setQuestionsModalVisible(false);
        }}
        width={600}
      >
        <Form
          form={questionForm}
          layout="vertical"
        >
          <Form.Item
            name="question"
            label="Question"
            rules={[{ required: true, message: 'Please enter question' }]}
          >
            <TextArea rows={3} placeholder="Enter your question" />
          </Form.Item>
          
          <Form.Item
            name="type"
            label="Question Type"
            rules={[{ required: true, message: 'Please select question type' }]}
          >
            <Select placeholder="Select question type">
              <Option value="multiple_choice">Multiple Choice</Option>
              <Option value="true_false">True/False</Option>
              <Option value="short_answer">Short Answer</Option>
              <Option value="essay">Essay</Option>
            </Select>
          </Form.Item>
          
          <Form.Item
            noStyle
            shouldUpdate={(prevValues, currentValues) => 
              prevValues.type !== currentValues.type
            }
          >
            {({ getFieldValue }) =>
              getFieldValue('type') === 'multiple_choice' ? (
                <Form.Item
                  name="options"
                  label="Options"
                  rules={[{ required: true, message: 'Please add options' }]}
                >
                  <Select
                    mode="tags"
                    placeholder="Add options (press Enter after each)"
                    style={{ width: '100%' }}
                  />
                </Form.Item>
              ) : null
            }
          </Form.Item>
          
          <Form.Item
            name="correctAnswer"
            label="Correct Answer"
            rules={[{ required: true, message: 'Please enter correct answer' }]}
          >
            <Input placeholder="Enter the correct answer" />
          </Form.Item>
          
          <Form.Item
            name="points"
            label="Points"
          >
            <InputNumber min={1} max={100} defaultValue={1} />
          </Form.Item>
        </Form>
      </Modal>
    </Layout>
  );
};

export default AdminFacultyDashboard;
